from typing import TypeVar, Generic, Sequence

# Simple generic
T = TypeVar('T')

def first(items: Sequence[T]) -> T:
    return items[0]

reveal_type(first([1, 2, 3]))       # int
reveal_type(first(['a', 'b']))      # str

# Constrained typevar
Number = TypeVar('Number', int, float, complex)
def add(a: Number, b: Number) -> Number:
    return a + b

# Bound typevar
class Model:
    def save(self): ...

M = TypeVar('M', bound=Model)

def save_all(models: list[M]) -> None:
    for m in models:
        m.save()

# Generic class
class Stack[T]:  # Python 3.12+; use Generic[T] for older
    def __init__(self) -> None:
        self._items: list[T] = []

    def push(self, item: T) -> None:
        self._items.append(item)

    def pop(self) -> T:
        return self._items.pop()

stack = Stack[int]()
stack.push(1)
reveal_type(stack.pop())  # int

from typing import Protocol, runtime_checkable

@runtime_checkable
class Drawable(Protocol):
    def draw(self) -> str: ...

class Circle:
    def draw(self) -> str:
        return 'circle'

class Square:
    def draw(self) -> str:
        return 'square'

class Dog:
    def bark(self) -> str:
        return 'woof'

def render(obj: Drawable) -> None:
    print(obj.draw())

render(Circle())  # OK
render(Square())  # OK
# render(Dog())   # mypy error: Dog doesn't implement Drawable

print(isinstance(Circle(), Drawable))  # True (with @runtime_checkable)
print(isinstance(Dog(), Drawable))     # False

# Protocol with multiple methods
class Comparable(Protocol):
    def __lt__(self, other) -> bool: ...

def sort_items(items: list[Comparable]) -> list[Comparable]:
    return sorted(items)

from typing import overload, TypedDict, Literal, assert_never

# === TypedDict ===
class User(TypedDict):
    id: int
    name: str
    email: str | None

user: User = {'id': 1, 'name': 'Alice', 'email': 'alice@example.com'}

# === Literal type ===
def set_mode(mode: Literal['r', 'w', 'a']) -> str:
    return f'mode set to {mode}'

set_mode('r')  # OK
# set_mode('x')  # mypy error

# === @overload ===
@overload
def parse(value: str) -> int: ...
@overload
def parse(value: list[str]) -> list[int]: ...
@overload
def parse(value: None) -> None: ...

def parse(value: str | list[str] | None) -> int | list[int] | None:
    if value is None:
        return None
    if isinstance(value, list):
        return [int(x) for x in value]
    return int(value)

reveal_type(parse('42'))      # int
reveal_type(parse(['1', '2']))  # list[int]
reveal_type(parse(None))      # None

# === exhaustiveness checking ===
def process_status(status: int | str) -> str:
    if isinstance(status, int):
        return f'code: {status}'
    elif isinstance(status, str):
        return f'message: {status}'
    else:
        assert_never(status)  # mypy error if new type added but not handled

from typing import TypeVar, ParamSpec, Concatenate, Callable
import functools

P = ParamSpec('P')
R = TypeVar('R')

# Decorator with preserved signature
def logged(func: Callable[P, R]) -> Callable[P, R]:
    @functools.wraps(func)
    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
        print(f'calling {func.__name__}')
        return func(*args, **kwargs)
    return wrapper

@logged
def add(a: int, b: int) -> int:
    return a + b

reveal_type(add)  # (int, int) -> int (preserved!)

# Concatenate: prepend parameters
S = TypeVar('S')
def with_logger(
    func: Callable[Concatenate[str, P], R]
) -> Callable[P, R]:
    @functools.wraps(func)
    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
        return func('[service]', *args, **kwargs)
    return wrapper

@with_logger
def process(logger: str, data: int) -> str:
    return f'{logger}: {data}'

reveal_type(process)  # (int) -> str (logger injected)
